messages.content:
RISKS:
[
 {
  "riskId": "risk.regulatory-gauntlet.cra-conformity-clock-outlasts-yam-window",
  "title": "Cyber Resilience Act (Reg. EU 2024/2847): the conformity clock for a networked PDU, started today, ends after the Year-1 window closes",
  "claim": "An intelligent PDU is a 'product with digital elements' under the CRA. Vulnerability-handling and 24h ENISA incident-reporting obligations apply from 11 September 2026 and full conformity (CE marking against CRA essential requirements, SBOM, coordinated vulnerability disclosure, support-period declaration) from 11 December 2027 — squarely overlapping a pre-launch venture's first 12 months. The harmonized standards CEN/CENELEC must deliver are not yet published, and remote-management functionality risks classifying the product as an 'important product' requiring third-party assessment through a notified-body queue that does not yet exist at scale. Worse, data-center buyers front-run: because PDUs installed in 2026 live in racks past 2027, procurement specs are already demanding CRA-readiness attestations today. The serviceableFactor's 0.55 haircut was built on the old CE/TÜV/ecodesign stack; it prices none of this, and the obtainableFactor's 1% Year-1 pace assumes the product can be quoted into 2026 tenders at all.",
  "falsifier": "Three 2026 CE data-center PDU RFQs (operator or colo) whose specification documents contain no CRA/cyber-conformity or SBOM requirement, plus confirmation that networked PDUs fall in the CRA default (self-assessment) class."
 },
 {
  "riskId": "risk.regulatory-gauntlet.mid-eichrecht-billing-metering-forecloses-german-colo",
  "title": "MID (2014/32/EU, MI-003) + German MessEG §32: billing-grade PDU metering in German colo is legally foreclosed without a legal-metrology approval the entrant cannot obtain in-window",
  "claim": "Half of this TAM is Germany, and the pitch of an INTELLIGENT PDU is metering. But the moment a colo uses PDU-level kWh data to bill sub-tenants, the meter falls under legal metrology: MID conformity (Annex MI-003) plus German MessEG obligations including §32 registration — a module B+D type-approval path through PTB/notified bodies that routinely takes 12–24 months and constrains the metering hardware design itself. The corpus already surfaced this (Eichrecht metering foreclosure) and noted that serviceableFactor's single qualitative haircut does not distinguish billing-grade from monitoring-grade demand. The kill path: the entrant's flagship feature is exactly the feature that is illegal to use for its highest-value purpose in its largest geography, so German colo tenders that specify 'MID-compliant outlet metering' — increasingly standard as EnEfG pushes operators toward measured billing — are closed to it. The 0.50 DE share silently assumes all German demand is equally reachable.",
  "falsifier": "A survey of German colo billing practice showing measured per-kWh sub-tenant billing remains marginal (capacity-tier/estimate-based dominating) AND no MID-metering requirement in a sample of 2026 German colo PDU specifications — or evidence the entrant's meter module already carries MID type approval."
 },
 {
  "riskId": "risk.regulatory-gauntlet.red-en18031-wireless-sensor-gate",
  "title": "RED cybersecurity delegated act (EU 2022/30, applicable since 1 Aug 2025): one WiFi sensor port drags the PDU into EN 18031 conformity and adds two quarters to launch",
  "claim": "If the intelligent PDU ships with any radio — WiFi management fallback, BLE commissioning, wireless environmental sensors — it is radio equipment, and since 1 August 2025 the Radio Equipment Directive's cybersecurity delegated act applies in full. Conformity runs against EN 18031-1/-2, which are harmonized only WITH RESTRICTIONS: where the restrictions bite (e.g., password/access-control configurations), self-declaration is unavailable and a notified body must issue an EU-type examination certificate. For a pre-launch team this is not a 2027 problem like the CRA — it is a today problem that gates the very first shipment. The obtainableFactor's 1% Year-1 anchor already sits on a corrected, fragile benchmark; a 4–6 month notified-body queue on top of an already pre-let, slow-procurement market compresses the sellable window from 12 months to 6–8.",
  "falsifier": "Confirmation that the launch SKU is wired-only (no radio in any shipping configuration), or an EN 18031 assessment showing the chosen access-control design falls entirely within the harmonized (self-declaration) scope with certificate in hand before first customer ship."
 },
 {
  "riskId": "risk.regulatory-gauntlet.avl-framework-qualification-forecloses-large-operator-cell",
  "title": "Buyer-side procurement norms (AVL qualification, ISO 27001/IEC 62443 attestations, global frameworks) close the chosen 40% large-operator beachhead for the entire Year-1 window",
  "claim": "The venture's stated beachhead is large operators — modeled as 40% of PDU spend. But that cell is not entered by winning a bake-off; it is entered by surviving an approved-vendor-list qualification: vendor security questionnaires demanding ISO 27001 and secure-development (IEC 62443-4-1) attestations, TÜV/CB-scheme type-test reports, factory audits, and financial-viability checks — a 12–18 month cycle that no law mandates and no market report prices. On top of that, the corpus shows the cell's spend is increasingly channelled through multi-year global frameworks (Digital Realty's $373M Schneider agreement, Iren's all-in Dell contract) and integrator bundles, meaning much of the nominal 0.40 is never tendered at PDU line-item level at all. The 0.40 value is an unsourced internal estimate; the reachable-in-window fraction of it is far smaller. The model books the beachhead as the largest cell; procurement norms make it the slowest.",
  "falsifier": "Two CE large operators confirming a fast-track vendor-qualification path (<6 months) for PDU suppliers and at least one 2026 PDU tender from a large CE operator that is open to non-AVL vendors."
 },
 {
  "riskId": "risk.regulatory-gauntlet.enefg-eed-reporting-spec-creep-dcim-lock",
  "title": "EnEfG §12 + EED Delegated Reg 2024/1364 reporting duties spec-crawl into PDU tenders as certified-accuracy + incumbent-DCIM-integration requirements",
  "claim": "Germany's Energy Efficiency Act obliges data centers to file energy and efficiency data to the Energieeffizienzregister annually (31 March), and the EU's 2024/1364 rating scheme adds a parallel Union-level reporting layer (annual 15 May filings). Neither instrument names PDUs — which is precisely why the model ignores them. But operators discharge these duties through their monitoring chain, so 2026 PDU specifications in Germany and beyond increasingly require certified metering accuracy classes plus validated integration with the incumbent DCIM suites (EcoStruxure, Vertiv Environet, Sunbird) that generate the filings. A new entrant's PDU without a certified accuracy declaration and pre-validated DCIM connectors fails the spec even when its own telemetry is superior — the reporting laws convert the incumbents' software ecosystems into a de facto certification the entrant lacks. The serviceableFactor's 0.55 was set against a product-law cert stack; it does not price an ecosystem-integration gate that binds hardest in the 50% German cell.",
  "falsifier": "A sample of 2026 German/Dutch colo PDU specifications showing no certified-accuracy or named-DCIM-integration requirements, or evidence that major DCIM suites accept open-protocol (SNMP/Redfish) PDU data for EnEfG/EED filings without vendor-specific validation."
 }
]

Emit JSON: { items: [{riskId, queries: [{query, kind: confirming|falsifying|base-rate}]}] } — 3 queries per risk.
